type Direction = 'UP' | 'DOWN' | 'LEFT' | 'RIGHT';
type Point = { x: number; y: number };
type Outcome = 'moved' | 'lost' | 'won';
type State = {
  snake: Point[];
  direction: Direction;
  bufferedDirection: Direction | null;
  food: Point | null;
  score: number;
};

const BOARD_SIZE = 14;
const STEP_MS = 140;
const INITIAL_SNAKE: Point[] = [
  { x: 6, y: 7 }, { x: 5, y: 7 }, { x: 4, y: 7 }
];
const INITIAL_FOOD: Point = { x: 8, y: 7 };
const DELTA: Record<Direction, Point> = {
  UP: { x: 0, y: -1 }, DOWN: { x: 0, y: 1 },
  LEFT: { x: -1, y: 0 }, RIGHT: { x: 1, y: 0 }
};
const OPPOSITE: Record<Direction, Direction> = {
  UP: 'DOWN', DOWN: 'UP', LEFT: 'RIGHT', RIGHT: 'LEFT'
};

function pointKey(point: Point): string {
  return String(point.x) + ',' + String(point.y);
}

function placeFood(snake: Point[], boardSize: number): Point | null {
  const occupied = new Set(snake.map(pointKey));
  const free: Point[] = [];
  for (let y = 0; y < boardSize; y += 1) {
    for (let x = 0; x < boardSize; x += 1) {
      const point = { x, y };
      if (!occupied.has(pointKey(point))) free.push(point);
    }
  }
  return free.length === 0
    ? null
    : free[Math.floor(Math.random() * free.length)];
}

function stepSnake(state: State, boardSize: number): State & { outcome: Outcome } {
  const direction = state.bufferedDirection ?? state.direction;
  const delta = DELTA[direction];
  const nextHead = {
    x: state.snake[0].x + delta.x,
    y: state.snake[0].y + delta.y
  };
  const base = { ...state, direction, bufferedDirection: null };
  const outOfBounds = nextHead.x < 0 || nextHead.y < 0 ||
    nextHead.x >= boardSize || nextHead.y >= boardSize;
  if (outOfBounds) return { ...base, outcome: 'lost' };

  const ateFood = state.food !== null && pointKey(nextHead) === pointKey(state.food);
  const bodyToCheck = ateFood ? state.snake : state.snake.slice(0, -1);
  if (bodyToCheck.some((part) => pointKey(part) === pointKey(nextHead))) {
    return { ...base, outcome: 'lost' };
  }

  const nextSnake = [nextHead, ...state.snake];
  if (!ateFood) {
    nextSnake.pop();
    return { ...base, snake: nextSnake, outcome: 'moved' };
  }

  const food = placeFood(nextSnake, boardSize);
  return {
    ...base,
    snake: nextSnake,
    food,
    score: state.score + 1,
    outcome: food === null ? 'won' : 'moved'
  };
}

class AppComponent {
  snake: Point[] = INITIAL_SNAKE.map((point) => ({ ...point }));
  direction: Direction = 'RIGHT';
  bufferedDirection: Direction | null = null;
  food: Point | null = { ...INITIAL_FOOD };
  isRunning = false;
  isGameOver = false;
  isWon = false;
  score = 0;
  private timerId: ReturnType<typeof setInterval> | null = null;

  onDirection(requested: Direction): void {
    if (this.bufferedDirection !== null) return;
    if (requested === this.direction || OPPOSITE[this.direction] === requested) return;
    this.bufferedDirection = requested;
  }

  start(): void {
    if (this.isRunning || this.isGameOver || this.isWon) return;
    this.isRunning = true;
    this.clearTimer();
    this.timerId = setInterval(() => this.tick(), STEP_MS);
  }

  reset(): void {
    this.clearTimer();
    this.snake = INITIAL_SNAKE.map((point) => ({ ...point }));
    this.direction = 'RIGHT';
    this.bufferedDirection = null;
    this.food = { ...INITIAL_FOOD };
    this.score = 0;
    this.isRunning = false;
    this.isGameOver = false;
    this.isWon = false;
  }

  private tick(): void {
    if (!this.isRunning || this.isGameOver || this.isWon) return;
    const result = stepSnake({
      snake: this.snake,
      direction: this.direction,
      bufferedDirection: this.bufferedDirection,
      food: this.food,
      score: this.score
    }, BOARD_SIZE);
    this.snake = result.snake;
    this.direction = result.direction;
    this.bufferedDirection = result.bufferedDirection;
    this.food = result.food;
    this.score = result.score;
    if (result.outcome === 'lost') {
      this.isGameOver = true;
      this.pause();
    } else if (result.outcome === 'won') {
      this.isWon = true;
      this.pause();
    }
  }

  private pause(): void {
    this.isRunning = false;
    this.clearTimer();
  }

  private clearTimer(): void {
    if (this.timerId !== null) {
      clearInterval(this.timerId);
      this.timerId = null;
    }
  }

  ngOnDestroy(): void {
    this.clearTimer();
  }
}
